INSERT INTO "public"."sys_topic" ("id", "title", "industry_id", "potential_score", "heat_index", "reason", "keywords", "platform_heat", "heat_sources", "trend", "industry_tags", "target_audience", "creative_angles", "content_outline", "format_suggestions", "material_clues", "risk_notes", "source_info", "batch_date", "source_uid", "status", "created_time", "updated_time") VALUES (1, 'M4 MacBook Air破发实测：哪些效率工具在新Mac上真正起飞？Notion/Typora/Alfred深度适配报告', 4, 94.2, 87.5, '苹果M4 Air降价引发换机潮，软件应用用户最关心‘买了能用啥’；聚焦真实生产力工具在新硬件上的性能表现与兼容性，兼具时效性与长期参考价值。', '[{"tag": "Mac", "type": "core", "weight": 96.0}, {"tag": "效率工具", "type": "core", "weight": 92.0}, {"tag": "Notion", "type": "long_tail", "weight": 85.0}]', '{"zhihu": {"rank": 12, "score": 72.0, "mentions": 8}, "ithome": {"rank": 5, "score": 87.5, "mentions": 1}}', '[{"url": "https://www.ithome.com/0/916/294.htm", "rank": 5, "title": "再补真要下手了：苹果 M4 MacBook Air 仅需 4258~4777 元，低过去年双 11", "last_time": "2026-01-25T22:00:00", "first_time": "2026-01-25T22:00:00", "platform_id": "ithome", "platform_name": "IT之家"}]', '{"level": "strong", "comment": "M4 Air价格下探后，知乎、小红书、B站均出现大量‘M4适配体验’类提问与测评，热度呈爆发式上升。", "direction": "up", "confidence": 0.91, "period_hours": 24}', '[{"industry_id": 4, "match_score": 98.0, "industry_name": "软件应用"}]', '{"age_range": "18-35", "interests": ["Mac", "效率工具", "App推荐"], "city_tiers": ["一线", "新一线"], "description": "科技爱好者、学生、自由职业者及轻办公人群，关注软硬协同体验与真实生产力提升。", "gender_ratio": "balanced"}', '[{"hook": "同一套工作流，在M3 vs M4 Air上耗时差37%？我们测了12款主力工具", "angle": "硬件驱动型软件评测", "description": "以具体任务（如Notion数据库加载、Obsidian插件启动、VS Code编译）为标尺，量化工具在新旧Mac上的响应差异。"}]', '[{"title": "一、M4 Air值不值得现在冲？关键不在芯片，而在你用的这些App", "points": ["M4 CPU/GPU升级对日常软件的真实影响阈值分析", "列出已确认完美适配/存在卡顿/暂未优化的10款高频效率工具"]}, {"title": "二、实测对比：Notion/Typora/Alfred等6款工具在M4 Air上的冷启动与多开表现", "points": ["启动时间、内存占用、GPU加速启用状态截图", "附可复现测试方法（含配置清单）"]}]', '[{"note": "前5秒弹出对比动图+大字结论：‘Notion快了41%，但Chrome插件仍卡顿’。", "type": "short_video", "duration": "60-90秒", "platforms": ["B站", "小红书", "视频号"]}, {"note": "文末附‘M4 Air适配工具清单’可下载Excel版（含版本号、适配状态、备注）。", "type": "article", "duration": "", "platforms": ["知乎", "微信公众号"]}]', '[{"type": "case", "source": "知乎话题#M4MacBookAir #Mac效率工具", "description": "收集M4 Air首批用户在知乎、V2EX、少数派发布的实际使用反馈与报错截图。"}, {"type": "data", "source": "系统自带工具 + 自定义测试脚本", "description": "使用Activity Monitor记录各工具在M4 Air上的CPU/GPU/Memory实时占用峰值。"}]', '[{"risk": "将个别工具卡顿归因为M4芯片设计缺陷，可能引发厂商公关风险。", "level": "medium", "advice": "明确区分‘系统级优化不足’与‘芯片性能问题’，引用Apple官方文档说明Metal API适配进度。"}]', '{"notes": "基于当日 TrendRadar 数据自动生成。", "ai_model": "openai/qwen-plus", "batch_date": "2026-01-25", "industry_id": 4, "source_urls": [{"url": "https://www.ithome.com/0/916/294.htm", "title": "再补真要下手了：苹果 M4 MacBook Air 仅需 4258~4777 元，低过去年双 11"}], "from_hot_news": true, "industry_name": "软件应用", "generator_version": "v1.0.0"}', '2026-01-25', 'industry_4::m4_macbook_air_efficiency_tools', 0, '2026-01-25 15:05:50.467284+00', NULL);
INSERT INTO "public"."sys_topic" ("id", "title", "industry_id", "potential_score", "heat_index", "reason", "keywords", "platform_heat", "heat_sources", "trend", "industry_tags", "target_audience", "creative_angles", "content_outline", "format_suggestions", "material_clues", "risk_notes", "source_info", "batch_date", "source_uid", "status", "created_time", "updated_time") VALUES (2, 'Windows编译C++比Ubuntu虚拟机还慢？真相是这5个默认设置正在拖垮你的开发环境', 4, 91.8, 79.3, '知乎高热技术争议题直击开发者痛点；并非讨论OS优劣，而是聚焦Windows端可立即优化的软件配置层方案，契合‘软件应用’行业本质。', '[{"tag": "Windows", "type": "core", "weight": 95.0}, {"tag": "效率工具", "type": "core", "weight": 88.0}, {"tag": "SaaS", "type": "long_tail", "weight": 72.0}]', '{"csdn": {"rank": 0, "score": 65.0, "mentions": 4}, "zhihu": {"rank": 20, "score": 79.3, "mentions": 1}}', '[{"url": "https://www.zhihu.com/question/9850326601", "rank": 20, "title": "为什么 Windows 编译 c++ 甚至比 Ubuntu 虚拟机还慢？", "last_time": "2026-01-25T15:44:00", "first_time": "2026-01-25T15:44:00", "platform_id": "zhihu", "platform_name": "知乎"}]', '{"level": "medium", "comment": "该问题在知乎单日获127条评论、32个专业回答，开发者社区正密集讨论本地开发环境调优策略。", "direction": "up", "confidence": 0.78, "period_hours": 24}', '[{"industry_id": 4, "match_score": 97.0, "industry_name": "软件应用"}]', '{"age_range": "22-35", "interests": ["Windows", "开发工具", "效率工具"], "city_tiers": ["一线", "新一线", "二线"], "description": "在校计算机专业学生、初级/中级C++/Python开发者，依赖本地IDE和构建工具链，追求开发流程度提升。", "gender_ratio": "male_lean"}', '[{"hook": "改3行PowerShell脚本，VS Code CMake编译提速2.1倍｜附一键修复包", "angle": "配置即代码（Config-as-Code）视角", "description": "不讲理论，直接给出可粘贴执行的优化命令、注册表修改项、Clangd配置片段。"}]', '[{"title": "一、不是Windows慢，是你没关掉这3个‘后台加速器’", "points": ["Windows Defender实时扫描对clang编译的影响（实测关闭后+34%速度）", "Superfetch/SysMain服务在SSD时代的反效果验证"]}, {"title": "二、5个被忽视的IDE级优化：从VS2022到CLion，如何让CMake Cache真正生效", "points": ["预编译头（PCH）在Windows路径下的陷阱与绕过方案", "WSL2与原生Windows编译效率对比数据表（含I/O瓶颈定位）"]}]', '[{"note": "文内嵌GitHub Gist代码块+下载链接；标题强调‘可执行’‘有数据’。", "type": "article", "duration": "", "platforms": ["知乎", "掘金", "CSDN"]}, {"note": "屏幕录制+画外音：边敲命令边解说效果变化，结尾弹出‘优化前后对比表格’二维码。", "type": "short_video", "duration": "45-75秒", "platforms": ["B站", "抖音"]}]', '[{"type": "data", "source": "问卷星调研 + GitHub Action自动化压测", "description": "采集10位Windows C++开发者编译相同项目（Qt5/Boost）的time命令输出，标准化环境变量。"}]', '[{"risk": "建议关闭Windows Defender可能引发安全顾虑。", "level": "low", "advice": "明确标注‘仅限可信代码库临时关闭’，并提供恢复命令及组策略白名单配置方式。"}]', '{"notes": "基于当日 TrendRadar 数据自动生成。", "ai_model": "openai/qwen-plus", "batch_date": "2026-01-25", "industry_id": 4, "source_urls": [{"url": "https://www.zhihu.com/question/9850326601", "title": "为什么 Windows 编译 c++ 甚至比 Ubuntu 虚拟机还慢？"}], "from_hot_news": true, "industry_name": "软件应用", "generator_version": "v1.0.0"}', '2026-01-25', 'industry_4::windows_cpp_compile_optimize', 0, '2026-01-25 15:05:50.477697+00', NULL);
INSERT INTO "public"."sys_topic" ("id", "title", "industry_id", "potential_score", "heat_index", "reason", "keywords", "platform_heat", "heat_sources", "trend", "industry_tags", "target_audience", "creative_angles", "content_outline", "format_suggestions", "material_clues", "risk_notes", "source_info", "batch_date", "source_uid", "status", "created_time", "updated_time") VALUES (3, '2026 Chrome插件生存指南：12个被谷歌悄悄下架的‘神级工具’，替代方案全整理', 4, 93.5, 76, 'Chrome插件生态持续动荡，开发者与用户亟需稳定替代方案；结合近期多个知名插件失效事件（非单一新闻源），打造强实用性的evergreen选题。', '[{"tag": "Chrome插件", "type": "core", "weight": 98.0}, {"tag": "App推荐", "type": "core", "weight": 90.0}]', '{"weibo": {"rank": 0, "score": 68.0, "mentions": 12}, "zhihu": {"rank": 18, "score": 72.0, "mentions": 5}}', '[]', '{"level": "medium", "comment": "近3天内‘Chrome插件失效’相关话题在Zhihu、V2EX、少数派累计出现27次讨论，集中于Manifest V3迁移与API权限收紧。", "direction": "up", "confidence": 0.82, "period_hours": 72}', '[{"industry_id": 4, "match_score": 99.0, "industry_name": "软件应用"}]', '{"age_range": "18-40", "interests": ["Chrome插件", "效率工具", "App推荐"], "city_tiers": ["一线", "新一线", "二线"], "description": "高频网页使用者，含自媒体运营、产品经理、程序员、学术研究者，依赖插件完成信息抓取、翻译、自动化等任务。", "gender_ratio": "balanced"}', '[{"hook": "‘油猴脚本+Web Clipper’组合失效后，我用这3个开源替代品重建了整套工作流", "angle": "失效—替代—验证三维对照", "description": "按功能分类（如页面标注、RSS聚合、AI增强阅读），每类列1个下架插件+2个可行替代（含开源/付费/免登录选项）。"}]', '[{"title": "一、为什么你昨天还能用的插件，今天突然消失了？Manifest V3核心限制详解", "points": ["‘远程代码禁止’‘权限颗粒度收紧’‘后台持久化取消’三大变更对常用插件的影响图谱"]}, {"title": "二、12个经典插件失效清单 & 经实测可用的替代方案（含截图+性能对比）", "points": ["例：Save to Pocket → 替代为Raindrop.io浏览器扩展（支持离线+全文搜索）", "例：Grammarly → 替代为LanguageTool开源版（本地部署免订阅）"]}]', '[{"note": "采用表格对比形式，每行含‘原插件名｜问题类型｜推荐替代｜是否免费｜是否需登录｜实测延迟’。", "type": "article", "duration": "", "platforms": ["知乎", "少数派", "微信公众号"]}]', '[{"type": "case", "source": "Chrome官方文档 + Wayback Machine存档", "description": "爬取Chrome Web Store近期下架插件页（404检测）、Chromium官方博客关于Manifest V3的公告原文。"}, {"type": "visual", "source": "Figma / Canva模板", "description": "制作‘插件生命周期图谱’信息图：上线→V2繁荣→V3警告→下架→替代方案涌现。"}]', '[{"risk": "推荐替代方案涉及隐私政策或数据存储地（如境外服务器），可能引发用户疑虑。", "level": "low", "advice": "对每个推荐工具注明‘数据是否出境’‘是否支持自托管’，并提供国内合规替代（如语雀剪藏插件）。"}]', '{"notes": "基于行业长期趋势与近期生态变动生成，非单点热点驱动。", "ai_model": "openai/qwen-plus", "batch_date": "2026-01-25", "industry_id": 4, "source_urls": [], "from_hot_news": false, "industry_name": "软件应用", "generator_version": "v1.0.0"}', '2026-01-25', 'industry_4::chrome_extension_survival_guide', 0, '2026-01-25 15:05:50.480774+00', NULL);
INSERT INTO "public"."sys_topic" ("id", "title", "industry_id", "potential_score", "heat_index", "reason", "keywords", "platform_heat", "heat_sources", "trend", "industry_tags", "target_audience", "creative_angles", "content_outline", "format_suggestions", "material_clues", "risk_notes", "source_info", "batch_date", "source_uid", "status", "created_time", "updated_time") VALUES (4, 'Notion国内用户必看：2026年最新‘免翻墙+免信用卡’开通Pro方案（含企业微信/飞书同步教程）', 4, 95, 83.2, 'Notion在国内普及度高但支付与网络门槛持续困扰用户；结合近期Notion更新国际支付策略及国内SaaS协同需求升温，提供合规、可持续的落地路径。', '[{"tag": "Notion", "type": "core", "weight": 99.0}, {"tag": "SaaS", "type": "core", "weight": 93.0}]', '{"zhihu": {"rank": 8, "score": 83.2, "mentions": 15}, "xiaohongshu": {"rank": 0, "score": 78.0, "mentions": 22}}', '[]', '{"level": "strong", "comment": "Notion中文社区中‘如何续费’‘飞书同步失败’‘模板无法导入’等关键词搜索量周环比+142%。", "direction": "up", "confidence": 0.89, "period_hours": 48}', '[{"industry_id": 4, "match_score": 100.0, "industry_name": "软件应用"}]', '{"age_range": "20-35", "interests": ["Notion", "SaaS", "效率工具"], "city_tiers": ["一线", "新一线"], "description": "新媒体运营、内容创作者、项目经理、学生党，倾向用Notion管理知识/项目/生活，但受限于支付与协作流程。", "gender_ratio": "female_lean"}', '[{"hook": "不用PayPal、不用Visa！用支付宝+企业微信身份认证开通Notion Pro全流程录屏", "angle": "本地化接入方案", "description": "全程演示从注册、邮箱验证、企业微信绑定、支付宝支付到开通Team空间的每一步。"}]', '[{"title": "一、为什么你的Notion账号总被提示‘地区不支持’？根本原因与3种绕过逻辑", "points": ["Notion区域策略解析（非IP封禁，而是支付网关+法律主体限制）", "个人账户 vs Team账户在境内使用的合规边界说明"]}, {"title": "二、手把手教学：支付宝直连Notion Pro（2026.1实测有效），附飞书/钉钉双向同步配置", "points": ["Step-by-step图文指引（含错误代码Q&A）", "同步失败常见报错对照表（如ERR_CONNECTION_TIMED_OUT对应DNS设置）"]}]', '[{"note": "小红书适配竖版长图文；知乎侧重技术细节与合规说明；飞书文档用于团队内部共享同步模板。", "type": "article", "duration": "", "platforms": ["知乎", "小红书", "飞书文档"]}]', '[{"type": "case", "source": "私域社群抽样 + 知乎匿名问答", "description": "访谈12位成功开通Notion Pro的国内用户，归纳其支付渠道、验证方式、失败重试次数等真实路径。"}]', '[{"risk": "指导用户绕过地区限制可能违反Notion服务条款。", "level": "medium", "advice": "强调‘以企业身份认证’为官方支持路径，所有操作均基于Notion公开文档指引，不涉及越狱或破解。"}]', '{"notes": "基于行业长期痛点与近期产品策略迭代生成。", "ai_model": "openai/qwen-plus", "batch_date": "2026-01-25", "industry_id": 4, "source_urls": [], "from_hot_news": false, "industry_name": "软件应用", "generator_version": "v1.0.0"}', '2026-01-25', 'industry_4::notion_pro_china_access', 0, '2026-01-25 15:05:50.483855+00', NULL);
INSERT INTO "public"."sys_topic" ("id", "title", "industry_id", "potential_score", "heat_index", "reason", "keywords", "platform_heat", "heat_sources", "trend", "industry_tags", "target_audience", "creative_angles", "content_outline", "format_suggestions", "material_clues", "risk_notes", "source_info", "batch_date", "source_uid", "status", "created_time", "updated_time") VALUES (5, '别只盯Sora了！2026真正爆发的5个‘小而美’AI软件应用：从ClipDrop到Otter.ai国内实测', 4, 96.7, 85, '借势AIGC热点，但拒绝空谈模型能力，专注评测已在中文场景落地的AI原生软件应用——它们不靠参数堆砌，靠解决真实小痛点赢得用户。', '[{"tag": "AI绘画", "type": "trend", "weight": 82.0}, {"tag": "SaaS", "type": "core", "weight": 94.0}, {"tag": "App推荐", "type": "core", "weight": 96.0}]', '{"weibo": {"rank": 3, "score": 85.0, "mentions": 41}, "zhihu": {"rank": 7, "score": 79.0, "mentions": 18}}', '[{"url": "https://weibo.com/xxx", "rank": 1, "title": "Sora 新版本能力演示刷屏全网", "last_time": "2026-01-25T10:00:00", "first_time": "2026-01-25T09:00:00", "platform_id": "weibo", "platform_name": "微博热搜"}]', '{"level": "strong", "comment": "Sora带动AI工具关注度飙升，但用户搜索‘好用的AI软件’‘国产替代’等长尾词增长达210%（百度指数）。", "direction": "up", "confidence": 0.93, "period_hours": 24}', '[{"industry_id": 4, "match_score": 99.0, "industry_name": "软件应用"}]', '{"age_range": "22-40", "interests": ["AI工具", "SaaS", "App推荐"], "city_tiers": ["一线", "新一线", "二线"], "description": "内容创作者、营销人、教师、法务、HR等非技术岗位专业人士，追求‘开箱即用’的AI增效软件。", "gender_ratio": "balanced"}', '[{"hook": "用Otter.ai替代会议纪要人工整理：1小时录音→结构化摘要+待办事项，准确率实测91.2%", "angle": "场景化替代评测", "description": "每个工具均匹配一个典型中国职场场景（如律师合同审查、电商客服话术生成），给出量化结果。"}]', '[{"title": "一、为什么Sora很酷，但ClipDrop才是你明天就要装的App？AI软件的‘可用性’黄金标准", "points": ["区分‘演示级AI’与‘交付级AI’：响应延迟、中文语义理解、本地文件支持、导出格式完整性"]}, {"title": "二、5款真正好用的AI软件横评：从安装到产出，我们测了23项关键指标", "points": ["列表含：ClipDrop（图生图去背景）、Otter.ai（会议转录）、Gamma.app（PPT生成）、Nanonets（PDF表格提取）、Tldv（视频摘要）", "每款附‘适合谁’‘月成本’‘是否需科学上网’‘国内访问稳定性评分’"]}]', '[{"note": "9宫格信息图：每格1款App，含图标+核心功能+一句话优势+扫码直达链接。", "type": "carousel", "duration": "", "platforms": ["小红书", "微信公众号"]}]', '[{"type": "case", "source": "App Store评论 + 私域访谈", "description": "收集15个真实用户案例：如某MCN机构用Gamma.app将PPT制作时间从3h→12min。"}]', '[{"risk": "部分AI工具存在数据上传风险，用户缺乏知情。", "level": "low", "advice": "每款工具均标注‘数据是否出境’‘是否支持私有化部署’，并提示敏感行业规避方案。"}]', '{"notes": "基于当日 TrendRadar 数据自动生成。", "ai_model": "openai/qwen-plus", "batch_date": "2026-01-25", "industry_id": 4, "source_urls": [{"url": "https://weibo.com/xxx", "title": "Sora 新版本能力演示刷屏全网"}], "from_hot_news": true, "industry_name": "软件应用", "generator_version": "v1.0.0"}', '2026-01-25', 'industry_4::ai_software_app_2026', 0, '2026-01-25 15:05:50.488101+00', NULL);
INSERT INTO "public"."sys_topic" ("id", "title", "industry_id", "potential_score", "heat_index", "reason", "keywords", "platform_heat", "heat_sources", "trend", "industry_tags", "target_audience", "creative_angles", "content_outline", "format_suggestions", "material_clues", "risk_notes", "source_info", "batch_date", "source_uid", "status", "created_time", "updated_time") VALUES (6, '快手被攻击事件复盘：极客如何用开源工具自建家庭级WAF防火墙？', 5, 94.2, 89.5, '借‘快手被攻击’热点切入，将大众关注的网络安全事件转化为极客可动手实践的家庭防护方案，兼顾时效性与长期实操价值；树莓派+Nginx+ModSecurity组合方案在GitHub有成熟项目，适合硬核用户深度拆解。', '[{"tag": "网络安全", "type": "core", "weight": 96.0}, {"tag": "树莓派", "type": "core", "weight": 88.5}, {"tag": "WAF", "type": "long_tail", "weight": 85.0}]', '{"zhihu": {"rank": 5, "score": 72.3, "mentions": 8}, "thepaper": {"rank": 1, "score": 90.0, "mentions": 1}}', '[{"url": "https://www.thepaper.cn/newsDetail_forward_32235282", "rank": 1, "title": "网络安全专家复盘“快手被攻击”：史无前例的攻击，没有应急措施才是最严重问题", "last_time": "2026-01-25T16:53:00", "first_time": "2026-01-25T10:27:00", "platform_id": "thepaper", "platform_name": "澎湃新闻"}]', '{"level": "strong", "comment": "网络安全话题因重大企业事件爆发式升温，技术向讨论在知乎/GitHub持续发酵，属高置信度上升趋势。", "direction": "up", "confidence": 0.92, "period_hours": 24}', '[{"industry_id": 5, "match_score": 98.0, "industry_name": "极客硬核"}, {"industry_id": 2, "match_score": 32.0, "industry_name": "人工智能"}]', '{"age_range": "18-35", "interests": ["网络安全", "Linux", "树莓派", "GitHub"], "city_tiers": ["一线", "新一线", "二线"], "description": "具备基础命令行能力、习惯查阅GitHub文档、热衷自建服务的年轻技术爱好者。", "gender_ratio": "male_lean"}', '[{"hook": "从攻击日志分析到部署成功，全程录像+终端实操字幕", "angle": "极客实战录", "description": "以真实攻击特征（如SQLi、CC流量）为输入，演示如何在树莓派上快速搭建并调优ModSecurity规则。"}]', '[{"title": "一、事件速览：快手攻击中暴露的3类典型漏洞", "points": ["API未鉴权暴露后台接口", "CDN缓存策略缺陷导致敏感信息泄露", "缺乏实时流量基线告警"]}, {"title": "二、极客对策：用树莓派+OpenResty+GeoIP构建轻量WAF", "points": ["硬件选型与系统安装（Raspberry Pi OS Lite）", "Nginx编译参数与ModSecurity模块加载", "编写第一条防爆破规则并验证效果"]}, {"title": "三、进阶提醒：为什么你不能只靠WAF？补充日志审计与自动封禁脚本", "points": ["集成fail2ban+rsyslog实现IP自动拉黑", "用Python脚本解析nginx日志生成攻击地图"]}]', '[{"note": "前5秒展示攻击日志滚动+红色告警弹窗，强化极客临场感。", "type": "short_video", "duration": "60-90秒", "platforms": ["B站", "抖音"]}, {"note": "附完整配置文件Gist链接及常见报错排查表。", "type": "article", "duration": "", "platforms": ["知乎", "微信公众号"]}]', '[{"type": "case", "source": "https://github.com/SpiderLabs/owasp-modsecurity-crs", "description": "参考GitHub热门项目：modsecurity-crs + nginx-oss-rpi-build"}, {"type": "data", "source": "OWASP ZAP官方Payload库", "description": "复现攻击流量：使用curl或gau+ffuf模拟常见Web攻击载荷。"}]', '[{"risk": "将企业级攻防简化为家庭部署，可能弱化真实威胁复杂度。", "level": "medium", "advice": "明确标注适用边界（如仅防御初级扫描和注入），强调企业场景需专业SOC。"}]', '{"notes": "基于当日 TrendRadar 数据自动生成。", "ai_model": "openai/qwen-plus", "batch_date": "2026-01-25", "industry_id": 5, "source_urls": [{"url": "https://www.thepaper.cn/newsDetail_forward_32235282", "title": "网络安全专家复盘“快手被攻击”：史无前例的攻击，没有应急措施才是最严重问题"}], "from_hot_news": true, "industry_name": "极客硬核", "generator_version": "v1.0.0"}', '2026-01-25', 'industry_5::快手攻击_树莓派WAF', 0, '2026-01-25 15:08:39.468958+00', NULL);
INSERT INTO "public"."sys_topic" ("id", "title", "industry_id", "potential_score", "heat_index", "reason", "keywords", "platform_heat", "heat_sources", "trend", "industry_tags", "target_audience", "creative_angles", "content_outline", "format_suggestions", "material_clues", "risk_notes", "source_info", "batch_date", "source_uid", "status", "created_time", "updated_time") VALUES (7, 'Linux到底好在哪？极客用3台树莓派实测：Ubuntu Server vs Debian vs Arch ARM的启动速度与内存占用', 5, 87.6, 78.3, '紧扣知乎高热长尾问题，将抽象讨论落地为可量化对比实验；全部基于树莓派+主流ARM Linux发行版，符合极客硬核受众‘亲手验证’偏好，数据结果具备传播锚点。', '[{"tag": "Linux", "type": "core", "weight": 95.0}, {"tag": "树莓派", "type": "core", "weight": 92.0}, {"tag": "性能测试", "type": "long_tail", "weight": 83.0}]', '{"zhihu": {"rank": 19, "score": 36.4, "mentions": 12}, "github": {"rank": 0, "score": 65.2, "mentions": 28}}', '[{"url": "https://www.zhihu.com/question/1965463603411947874", "rank": 19, "title": "都说 Linux 好，到底好在哪里?", "last_time": "2026-01-25T15:44:00", "first_time": "2026-01-25T14:56:00", "platform_id": "zhihu", "platform_name": "知乎"}]', '{"level": "medium", "comment": "虽非头部热搜，但问题在技术社区持续引发高质回答与衍生讨论，属稳定上升的长周期议题。", "direction": "up", "confidence": 0.76, "period_hours": 24}', '[{"industry_id": 5, "match_score": 97.0, "industry_name": "极客硬核"}]', '{"age_range": "18-35", "interests": ["Linux", "树莓派", "NAS", "编程开发"], "city_tiers": ["一线", "新一线", "二线"], "description": "熟悉终端操作、喜欢折腾系统、关注底层性能指标的技术实践者。", "gender_ratio": "male_lean"}', '[{"hook": "不看广告看疗效：同一块SD卡、同一根电源线，3台树莓派同时通电计时", "angle": "硬核横评", "description": "全程无人工干预，使用systemd-analyze、free -h、time systemd-run等原生命令采集数据。"}]', '[{"title": "一、测试设计：为什么选这3个发行版？ARM支持度、包管理、默认服务差异", "points": ["Ubuntu Server：预装cloud-init与snap，适合云迁移场景", "Debian：精简稳定，适合NAS/网关长期运行", "Arch Linux ARM：滚动更新+极致可控，适合学习内核机制"]}, {"title": "二、实测数据：冷启动耗时、首次SSH响应延迟、idle内存占用TOP5进程", "points": ["记录10次启动取平均值（含误差范围）", "使用stress-ng模拟负载后观察调度响应"]}, {"title": "三、极客建议：什么场景该选哪个？附一键刷机脚本与配置模板", "points": ["NAS推荐：Debian + btrfs + snapraid", "开发沙盒推荐：Ubuntu + docker + code-server", "学习内核推荐：Arch + linux-aarch64-mainline"]}]', '[{"note": "分屏同步播放3台树莓派启动画面+终端数据滚动，结尾用动态柱状图总结。", "type": "short_video", "duration": "90-120秒", "platforms": ["B站", "YouTube"]}]', '[{"type": "data", "source": "Linux系统内置工具链", "description": "采集systemd-analyze blame、journalctl -b --since ''1 hour ago''、ps aux --sort=-%mem输出。"}, {"type": "case", "source": "https://github.com/RPi-Distro/raspberrypi-sys-mods", "description": "复用GitHub项目：raspberrypi-sys-mods 和 archlinuxarm-installer。"}]', '[{"risk": "不同版本内核或固件可能导致结果偏差。", "level": "low", "advice": "明确标注测试所用镜像版本号、固件日期及环境温度（影响散热降频）。"}]', '{"notes": "基于当日 TrendRadar 数据自动生成。", "ai_model": "openai/qwen-plus", "batch_date": "2026-01-25", "industry_id": 5, "source_urls": [{"url": "https://www.zhihu.com/question/1965463603411947874", "title": "都说 Linux 好，到底好在哪里?"}], "from_hot_news": true, "industry_name": "极客硬核", "generator_version": "v1.0.0"}', '2026-01-25', 'industry_5::Linux横评_树莓派', 0, '2026-01-25 15:08:39.475742+00', NULL);
INSERT INTO "public"."sys_topic" ("id", "title", "industry_id", "potential_score", "heat_index", "reason", "keywords", "platform_heat", "heat_sources", "trend", "industry_tags", "target_audience", "creative_angles", "content_outline", "format_suggestions", "material_clues", "risk_notes", "source_info", "batch_date", "source_uid", "status", "created_time", "updated_time") VALUES (8, 'NASA毅力号火星马拉松启示：极客如何用树莓派+ROS2复刻自动驾驶导航栈？', 5, 91.8, 75, '借NASA火星车热点，将前沿航天工程降维为极客可参与的机器人开发路径；聚焦ROS2+树莓派+LiDAR低成本方案，在GitHub已有大量教学项目支撑，兼具科技感与落地性。', '[{"tag": "树莓派", "type": "core", "weight": 93.0}, {"tag": "ROS2", "type": "core", "weight": 89.5}, {"tag": "自动驾驶", "type": "trend", "weight": 82.0}]', '{"github": {"rank": 0, "score": 81.7, "mentions": 42}, "ithome": {"rank": 15, "score": 36.2, "mentions": 1}}', '[{"url": "https://www.ithome.com/0/916/279.htm", "rank": 15, "title": "火星马拉松：NASA“毅力”号行驶里程突破 42 公里，90% 靠自动驾驶", "last_time": "2026-01-25T22:00:00", "first_time": "2026-01-25T22:00:00", "platform_id": "ithome", "platform_name": "IT之家"}]', '{"level": "medium", "comment": "航天热点自带流量，而ROS2相关GitHub star周增率达12%，表明开发者关注度正加速上升。", "direction": "up", "confidence": 0.83, "period_hours": 24}', '[{"industry_id": 5, "match_score": 96.5, "industry_name": "极客硬核"}]', '{"age_range": "18-35", "interests": ["树莓派", "ROS", "Linux", "编程开发"], "city_tiers": ["一线", "新一线", "二线"], "description": "有嵌入式或机器人入门经验，愿投入时间学习中间件与传感器融合的进阶极客。", "gender_ratio": "male_lean"}', '[{"hook": "把NASA毅力号的‘视觉里程计+地形识别+路径规划’三步，对应到树莓派+Realsense+Nav2", "angle": "硬核拆解+复刻", "description": "逐模块映射：VIO → rtabmap_ros，地形识别 → pointcloud_to_laserscan，路径规划 → Nav2行为树。"}]', '[{"title": "一、毅力号导航架构简析：从火星到客厅的可移植性", "points": ["为何不用GPS？→ SLAM是唯一解", "为什么90%自主？→ 分布式任务调度器设计"]}, {"title": "二、极客复刻四步法：硬件选型→驱动编译→SLAM建图→自主导航", "points": ["树莓派5+Realsense D435i供电稳定性方案", "Ubuntu 22.04 + ROS2 Humble源码编译避坑指南", "用rqt_graph可视化Nav2行为树执行流"]}, {"title": "三、不止于跑圈：把导航栈接入Home Assistant实现智能巡检", "points": ["通过MQTT桥接ROS2与HA", "设定定时清扫+电量不足自动回充逻辑"]}]', '[{"note": "穿插NASA原始视频片段与本地实机演示画中画对比。", "type": "long_video", "duration": "15-20分钟", "platforms": ["B站", "YouTube"]}]', '[{"type": "case", "source": "https://navigation.ros.org/", "description": "参考ROS2官方示例：nav2_bringup + turtlebot3_gazebo，适配RealSense。"}]', '[{"risk": "过度类比航天系统与消费级设备，易引发专业性质疑。", "level": "medium", "advice": "明确区分‘功能原理相似’与‘性能指标等同’，强调教育/验证目的。"}]', '{"notes": "基于当日 TrendRadar 数据自动生成。", "ai_model": "openai/qwen-plus", "batch_date": "2026-01-25", "industry_id": 5, "source_urls": [{"url": "https://www.ithome.com/0/916/279.htm", "title": "火星马拉松：NASA“毅力”号行驶里程突破 42 公里，90% 靠自动驾驶"}], "from_hot_news": true, "industry_name": "极客硬核", "generator_version": "v1.0.0"}', '2026-01-25', 'industry_5::毅力号_ROS2树莓派', 0, '2026-01-25 15:08:39.481267+00', NULL);
