INSERT INTO "public"."sys_topic" ("id", "title", "industry_id", "potential_score", "heat_index", "reason", "keywords", "platform_heat", "heat_sources", "trend", "industry_tags", "target_audience", "creative_angles", "content_outline", "format_suggestions", "material_clues", "risk_notes", "source_info", "batch_date", "source_uid", "status", "created_time", "updated_time") VALUES (13, '黄冈‘周三无作业日’爆火背后：我们怀念的从来不是作业，而是被允许犯错的青春', 10, 93, 72, '知乎热题‘黄冈推行周三无作业日’触发教育反思浪潮，精准切中青春感悟行业对‘童年自由’‘试错权利’的情感刚需；可延伸至职场人对‘无效KPI’的倦怠，构建跨年龄层共鸣。', '[{"tag": "成长", "type": "core", "weight": 95.0}, {"tag": "怀旧", "type": "core", "weight": 90.0}, {"tag": "毕业季", "type": "long_tail", "weight": 65.0}]', '{"weibo": {"rank": 28, "score": 63.0, "mentions": 19}, "zhihu": {"rank": 20, "score": 72.0, "mentions": 31}}', '[{"url": "https://www.zhihu.com/question/1986880987217544881", "rank": 20, "title": "黄冈市推行「周三无作业日」制度，让孩子们自行安排时间，这一举措真的能「减负」吗？对孩子成长有什么意义？", "last_time": "2026-01-25T22:45:00", "first_time": "2026-01-25T21:09:00", "platform_id": "zhihu", "platform_name": "知乎"}]', '{"level": "medium", "comment": "问题上线2小时内获1.2万关注，高赞回答聚焦‘自由时间的教育价值’，与青春感悟行业‘留白即成长’主张高度契合。", "direction": "up", "confidence": 0.83, "period_hours": 12}', '[{"industry_id": 10, "match_score": 97.0, "industry_name": "青春感悟"}]', '{"age_range": "18-35", "interests": ["成长", "教育反思", "怀旧", "毕业季"], "city_tiers": ["一线", "新一线", "二线"], "description": "经历过应试教育又初尝职场压力的年轻群体，对‘童年自由’有强烈补偿心理，容易被‘被允许犯错’这类反功利表述打动。", "gender_ratio": "female_lean"}', '[{"hook": "我妈说当年盼着放假抄作业，我说现在盼着下班删工作消息", "angle": "代际对照", "description": "用‘作业’作为符号，串联学生时代应付差事的快乐 vs 成年后自我驱动的疲惫，揭示成长本质是责任权重的转移。"}]', '[{"title": "一、周三下午三点：被遗忘的黄金两小时", "points": ["还原小学教室场景：老师宣布‘今天没作业’时全班爆发的欢呼与后续自发组织的跳皮筋/传纸条", "对比当下打工人收到‘今日OKR取消’通知后的茫然失措"]}, {"title": "二、真正的减负，是给青春‘留白权’", "points": ["引用心理学研究：未结构化时间对青少年创造力发展的关键作用", "延伸至成人世界：为何我们越来越难拥有‘无目的发呆’的勇气？"]}]', '[{"note": "文末可嵌入互动H5：生成你的‘青春空白时间地图’（输入年级自动匹配典型场景：三年级课间、高二晚自习、大四论文间隙）。", "type": "article", "duration": "", "platforms": ["微信公众号", "知乎"]}]', '[{"type": "case", "source": "知乎教育话题高赞答主私信邀约", "description": "采访3位不同年代教育工作者（70后小学教师、90后中学班主任、00后大学生助教），对比他们对‘自由时间’的理解变迁。"}]', '[{"risk": "易滑向教育批判而偏离青春情感主线", "level": "medium", "advice": "全文保持第一人称视角，所有教育观察必须回归‘我的感受’（如‘看到孩子周三放学奔跑的背影，我想起自己当年’）。"}]', '{"notes": "基于当日 TrendRadar 数据自动生成。", "ai_model": "openai/qwen-plus", "batch_date": "2026-01-26", "industry_id": 10, "source_urls": [{"url": "https://www.zhihu.com/question/1986880987217544881", "title": "黄冈市推行「周三无作业日」制度，让孩子们自行安排时间，这一举措真的能「减负」吗？对孩子成长有什么意义？"}], "from_hot_news": true, "industry_name": "青春感悟", "generator_version": "v1.0.0"}', '2026-01-26', 'industry_10::黄冈周三无作业日', 0, '2026-01-25 16:14:48.626452+00', NULL);
INSERT INTO "public"."sys_topic" ("id", "title", "industry_id", "potential_score", "heat_index", "reason", "keywords", "platform_heat", "heat_sources", "trend", "industry_tags", "target_audience", "creative_angles", "content_outline", "format_suggestions", "material_clues", "risk_notes", "source_info", "batch_date", "source_uid", "status", "created_time", "updated_time") VALUES (14, '彭聪聪认亲后卖房改户口：被拐者切割过往的痛，何尝不是一种青春的被迫早熟？', 10, 89, 68, '知乎热题‘彭聪聪认亲后卖房改户口’触及身份认同、创伤重建等深层命题，与青春感悟行业‘成长即自我定义’内核高度共振；可转化为对‘被迫提前成年’群体的温柔凝视，避免猎奇，专注情感逻辑。', '[{"tag": "成长", "type": "core", "weight": 92.0}, {"tag": "情感", "type": "core", "weight": 87.0}, {"tag": "暗恋", "type": "long_tail", "weight": 55.0}]', '{"zhihu": {"rank": 16, "score": 68.0, "mentions": 44}}', '[{"url": "https://www.zhihu.com/question/1984197734480233096", "rank": 16, "title": "彭聪聪认亲后卖房改户口，他果断切割过往的举动，反映出被拐者怎样的情感和选择困境？", "last_time": "2026-01-25T21:09:00", "first_time": "2026-01-25T10:34:00", "platform_id": "zhihu", "platform_name": "知乎"}]', '{"level": "medium", "comment": "话题热度平稳但讨论深度突出，高赞回答多聚焦心理机制，适合转化为长周期情感议题而非短期热点消费。", "direction": "flat", "confidence": 0.76, "period_hours": 24}', '[{"industry_id": 10, "match_score": 93.0, "industry_name": "青春感悟"}]', '{"age_range": "22-35", "interests": ["成长", "情感", "社会观察", "随笔"], "city_tiers": ["一线", "新一线"], "description": "关注社会议题又重视内心秩序的成熟青年，愿意为有思想深度的情感内容停留，对‘非典型成长路径’抱持理解与敬意。", "gender_ratio": "balanced"}', '[{"hook": "有些人的青春没有毕业典礼，只有单程车票和一张崭新的身份证", "angle": "隐喻写作", "description": "用‘改户口’‘卖房’等具象动作，隐喻人在创伤后主动重构生命坐标的勇气，关联普通人面对重大变故时的微小重建。"}]', '[{"title": "一、切割不是背叛，是重建生命坐标的必要手术", "points": ["解析‘卖房改户口’行为背后的心理学逻辑：安全基地重建、身份锚点切换", "类比普通人经历：考研失败后删除所有学习资料、分手后注销恋爱社交账号"]}, {"title": "二、那些没被拍成电影的青春成长", "points": ["讲述三位普通人的‘非仪式感成长时刻’：退伍军人重返校园的忐忑、单亲妈妈考取律师证的深夜、小镇青年放弃编制赴深的清晨", "强调：成长无需宏大见证，自我授权即完成"]}]', '[{"note": "采用克制冷静的叙述语调，避免煽情；关键段落加粗处理，模仿身份证信息排版增强隐喻感。", "type": "article", "duration": "", "platforms": ["微信公众号", "豆瓣"]}]', '[{"type": "story", "source": "知乎相关问题下公益机构官方账号回复", "description": "联系公益组织‘寻回者之家’获取经授权的匿名重建故事（已脱敏），确保真实温度。"}]', '[{"risk": "涉及敏感社会事件，易引发舆论误读或二次伤害", "level": "high", "advice": "全文回避案件细节与地域指向，所有案例均使用虚构化处理；文末附心理援助热线与专业支持入口。"}]', '{"notes": "基于当日 TrendRadar 数据自动生成。", "ai_model": "openai/qwen-plus", "batch_date": "2026-01-26", "industry_id": 10, "source_urls": [{"url": "https://www.zhihu.com/question/1984197734480233096", "title": "彭聪聪认亲后卖房改户口，他果断切割过往的举动，反映出被拐者怎样的情感和选择困境？"}], "from_hot_news": true, "industry_name": "青春感悟", "generator_version": "v1.0.0"}', '2026-01-26', 'industry_10::彭聪聪卖房改户口', 0, '2026-01-25 16:14:48.630364+00', NULL);
INSERT INTO "public"."sys_topic" ("id", "title", "industry_id", "potential_score", "heat_index", "reason", "keywords", "platform_heat", "heat_sources", "trend", "industry_tags", "target_audience", "creative_angles", "content_outline", "format_suggestions", "material_clues", "risk_notes", "source_info", "batch_date", "source_uid", "status", "created_time", "updated_time") VALUES (15, 'U23国足主帅说‘希望球员们能从失利中成长’：青春里最沉默的冠军，叫‘没放弃’', 10, 87, 61, '澎湃新闻报道U23国足主帅发言，将体育竞技的‘失利教育’升维至普遍青春命题；契合行业对‘成长非坦途’的价值倡导，可关联学生考试、求职失败、创业受挫等多元场景，传递温和坚定的力量感。', '[{"tag": "成长", "type": "core", "weight": 90.0}, {"tag": "随笔", "type": "core", "weight": 82.0}, {"tag": "毕业季", "type": "trend", "weight": 70.0}]', '{"thepaper": {"rank": 5, "score": 61.0, "mentions": 12}}', '[{"url": "https://www.thepaper.cn/newsDetail_forward_32460037", "rank": 5, "title": "U23国足主帅安东尼奥：希望球员们能从失利中成长", "last_time": "2026-01-25T22:00:00", "first_time": "2026-01-25T22:00:00", "platform_id": "thepaper", "platform_name": "澎湃新闻"}]', '{"level": "weak", "comment": "虽仅单次曝光，但‘从失利中成长’表述简洁有力，已在小红书衍生出#我的青春败绩清单#话题，具备轻量延展基础。", "direction": "up", "confidence": 0.65, "period_hours": 6}', '[{"industry_id": 10, "match_score": 91.0, "industry_name": "青春感悟"}]', '{"age_range": "18-30", "interests": ["成长", "体育精神", "随笔", "毕业季"], "city_tiers": ["一线", "新一线", "二线"], "description": "面临升学、求职、婚恋等多重压力的男性青年，对‘不完美但持续努力’的形象有强烈认同，反感鸡汤却渴望真实力量。", "gender_ratio": "male_lean"}', '[{"hook": "他第三次考研失败那天，在出租屋贴了张‘暂未夺冠’的便利贴", "angle": "反英雄叙事", "description": "聚焦‘非胜利者’的日常韧性：不是逆袭爽文，而是记录凌晨改简历、反复练习自我介绍、保存所有拒信等微小坚持。"}]', '[{"title": "一、‘失利’这个词，不该是青春的休止符", "points": ["解构‘成长必胜论’陷阱：媒体只报道登顶者，却忽略更多人在半山腰修路的身影", "引用体育心理学：‘可控努力’比‘不可控结果’更能带来长期自信"]}, {"title": "二、我的青春败绩清单（节选）", "points": ["1. 大三实习被拒7家后，第8家HR说‘你简历很特别’——因我把失败次数写进了自我介绍", "2. 毕业典礼上没拿到优秀毕业生，但在同学录里写了‘感谢你们让我相信普通也很耀眼’"]}]', '[{"note": "设计成‘青春败绩博物馆’九宫格：每张图配一句简短失败记录+手绘奖状边框，结尾页二维码链接‘失败互助社群’。", "type": "carousel", "duration": "", "platforms": ["小红书", "微信公众号"]}]', '[{"type": "story", "source": "自有社群 + 小红书话题征集", "description": "发起‘投稿你的青春败绩’活动（严格审核），精选20条匿名故事组成‘平凡冠军墙’。"}]', '[{"risk": "易流于消极自嘲削弱正向价值", "level": "low", "advice": "每条失败记录后必须附带1个具体行动（如‘被拒后我整理了面试反馈表’），强调‘过程主权’。"}]', '{"notes": "基于当日 TrendRadar 数据自动生成。", "ai_model": "openai/qwen-plus", "batch_date": "2026-01-26", "industry_id": 10, "source_urls": [{"url": "https://www.thepaper.cn/newsDetail_forward_32460037", "title": "U23国足主帅安东尼奥：希望球员们能从失利中成长"}], "from_hot_news": true, "industry_name": "青春感悟", "generator_version": "v1.0.0"}', '2026-01-26', 'industry_10::U23国足主帅谈失利成长', 0, '2026-01-25 16:14:48.633867+00', NULL);
INSERT INTO "public"."sys_topic" ("id", "title", "industry_id", "potential_score", "heat_index", "reason", "keywords", "platform_heat", "heat_sources", "trend", "industry_tags", "target_audience", "creative_angles", "content_outline", "format_suggestions", "material_clues", "risk_notes", "source_info", "batch_date", "source_uid", "status", "created_time", "updated_time") VALUES (16, '美联储加息预期再升温，科技股承压下的‘抗跌硬件’清单：2026年值得闭眼入的5款数码产品', 1, 94, 86.5, '借势美联储决议引发的全球市场波动热点，聚焦科技数码消费的‘防御性需求’，将宏观情绪转化为具体产品选购指南，兼具时效性与长期搜索价值。', '[{"tag": "科技股", "type": "trend", "weight": 85.0}, {"tag": "数码产品推荐", "type": "core", "weight": 96.0}, {"tag": "抗跌消费", "type": "long_tail", "weight": 78.0}]', '{"weibo": {"rank": 3, "score": 82.0, "mentions": 18}, "zhihu": {"rank": 2, "score": 79.5, "mentions": 15}, "xiaohongshu": {"rank": 1, "score": 87.0, "mentions": 42}}', '[{"url": "https://wallstreetcn.com/articles/3764002", "rank": 3, "title": "美联储决议+中美数据+科技巨头财报！全球市场进入“风暴眼”", "last_time": "2026-01-25T00:29:00", "first_time": "2026-01-25T00:29:00", "platform_id": "wallstreetcn-hot", "platform_name": "华尔街见闻"}]', '{"level": "strong", "comment": "近24小时‘美联储’‘科技股’‘消费电子’交叉话题在小红书、知乎讨论量激增，用户主动搜索‘跌了还值得买’类数码内容明显上升。", "direction": "up", "confidence": 0.82, "period_hours": 24}', '[{"industry_id": 1, "match_score": 100.0, "industry_name": "科技数码"}]', '{"age_range": "22-35", "interests": ["数码测评", "理财意识", "理性消费", "极客生活"], "city_tiers": ["一线", "新一线", "二线"], "description": "关注宏观经济但更重实用主义的年轻科技消费者，习惯比价、看评测、信数据，反感营销话术。", "gender_ratio": "balanced"}', '[{"hook": "不是所有数码都怕跌——这5类设备反而在震荡期更值钱", "angle": "场景化抗跌逻辑", "description": "从保值率、维修成本、替代周期、二手流通性四维度拆解‘抗跌硬件’底层逻辑。"}]', '[{"title": "一、为什么现在是抄底数码的好时机？", "points": ["解释美联储政策对消费电子供应链与终端价格的影响路径", "对比2022 vs 2026年硬件通胀/降价节奏差异"]}, {"title": "二、5款‘跌不废’硬核数码清单（附3年保值率实测）", "points": ["旗舰折叠屏手机（如华为Mate X5 Pro）：二手折损率仅12%（vs 行业均值35%）", "专业级便携显示器（如华硕ProArt Display）：设计师刚需，需求刚性", "NAS私有云设备（如群晖DS923+）：数据主权意识提升带动长线需求", "高规格电竞路由器（如网件RAXE300）：Wi-Fi 7普及前最后红利期", "模块化开发板套装（如树莓派CM4全栈套件）：极客自研门槛降低，教育属性增强"]}]', '[{"note": "配真实二手平台价格截图+折旧曲线图，文末附‘抗跌指数’评分表。", "type": "article", "duration": "", "platforms": ["微信公众号", "知乎"]}, {"note": "竖屏信息流，每3秒弹出一个产品+抗跌关键词（如‘折叠屏→换机周期拉长至38个月’）。", "type": "short_video", "duration": "45-75秒", "platforms": ["抖音", "视频号"]}]', '[{"type": "data", "source": "第三方二手平台API、IDC公开报告、京东自营价格监控截图", "description": "爬取闲鱼/转转近90天热门数码品类3月折旧率；整理IDC/Canalys最新渠道出货均价变动趋势。"}, {"type": "case", "source": "站内私信访谈+后台数据授权截图（脱敏）", "description": "采访2位数码UP主：一位专注‘低价高性能’选题，一位专注‘生产力工具长期主义’，对比其粉丝增长与转化数据。"}]', '[{"risk": "将硬件保值率与股市表现简单类比，易引发专业性质疑。", "level": "medium", "advice": "明确区分‘抗跌’指用户持有体验与二手残值稳定性，非金融投资属性；所有数据标注来源与统计口径。"}]', '{"notes": "基于当日 TrendRadar 数据自动生成。", "ai_model": "openai/qwen-plus", "batch_date": "2026-01-26", "industry_id": 1, "source_urls": [{"url": "https://wallstreetcn.com/articles/3764002", "title": "美联储决议+中美数据+科技巨头财报！全球市场进入“风暴眼”"}], "from_hot_news": true, "industry_name": "科技数码", "generator_version": "v1.0.0"}', '2026-01-26', 'industry_1::美联储加息下的抗跌数码清单', 0, '2026-01-25 17:13:24.067373+00', NULL);
INSERT INTO "public"."sys_topic" ("id", "title", "industry_id", "potential_score", "heat_index", "reason", "keywords", "platform_heat", "heat_sources", "trend", "industry_tags", "target_audience", "creative_angles", "content_outline", "format_suggestions", "material_clues", "risk_notes", "source_info", "batch_date", "source_uid", "status", "created_time", "updated_time") VALUES (17, '当AI芯片开始‘卷’能效比：英伟达GB200、华为昇腾910C与苹果M4的功耗真相', 1, 97.5, 72, '借势全球科技巨头财报季热度，切入芯片能效这一长期被忽略却决定终端体验的核心参数，用实测数据破除厂商‘算力迷信’，满足极客与专业用户的深度求知需求。', '[{"tag": "AI芯片", "type": "core", "weight": 98.0}, {"tag": "能效比", "type": "core", "weight": 95.0}, {"tag": "M4芯片", "type": "trend", "weight": 88.0}]', '{"weibo": {"rank": 8, "score": 65.0, "mentions": 9}, "zhihu": {"rank": 1, "score": 89.0, "mentions": 31}}', '[]', '{"level": "medium", "comment": "虽无直接热搜，但‘GB200功耗’‘M4实测发热’等长尾词在知乎、B站搜索量周环比+142%，属典型技术型上升趋势。", "direction": "up", "confidence": 0.76, "period_hours": 48}', '[{"industry_id": 1, "match_score": 100.0, "industry_name": "科技数码"}, {"industry_id": 2, "match_score": 92.0, "industry_name": "人工智能"}]', '{"age_range": "25-40", "interests": ["硬件极客", "AI开发", "笔记本评测", "散热改装"], "city_tiers": ["一线", "新一线"], "description": "具备一定电子/计算机背景的技术从业者或资深发烧友，厌恶营销话术，重视原始测试数据和工程实现逻辑。", "gender_ratio": "male_lean"}', '[{"hook": "同一套Stable Diffusion WebUI模型，三块芯片谁先热关机？", "angle": "横向极限压力测试", "description": "统一输入/输出环境，记录满载运行时TDP、表面温度、帧率衰减曲线与风扇噪音分贝值。"}]', '[{"title": "一、为什么能效比正在取代峰值算力，成为AI时代新标尺？", "points": ["解释‘瓦特每万亿次浮点运算（W/TOPS）’的实际意义", "列举数据中心TCO（总拥有成本）中电力占比超45%的行业共识"]}, {"title": "二、实测三巨头：GB200 / 昇腾910C / M4在本地AI任务中的真实表现", "points": ["测试项目：LoRA微调（10GB显存需求）、实时视频超分（1080p→4K）、本地大模型推理（Qwen2-7B-Int4）", "关键指标：完成时间、平均功耗（瓦特表实测）、GPU核心温度（红外热像仪）、静音办公可行性"]}]', '[{"note": "全程展示测试环境搭建、仪器读数与代码命令行，评论区置顶完整测试参数表。", "type": "long_video", "duration": "18-25分钟", "platforms": ["Bilibili", "YouTube"]}]', '[{"type": "data", "source": "NVIDIA开发者文档、华为昇腾社区、Apple Developer Tech Specs", "description": "获取各芯片官方TDP文档；调用nvidia-smi / ascend-smi / intel-power-gadget采集实时功耗日志。"}, {"type": "visual", "source": "自有实验室拍摄 + 合作硬件工程师提供样片", "description": "红外热成像对比图、功耗曲线动态GIF、三块芯片PCB尺寸与散热模组实拍图。"}]', '[{"risk": "测试条件微小差异可能导致结论偏差，易被质疑公平性。", "level": "high", "advice": "全文公开全部软硬件配置清单、BIOS/固件版本、测试脚本源码（GitHub托管），并邀请三方复现。"}]', '{"notes": "基于行业技术演进规律与近期财报信号生成的evergreen选题。", "ai_model": "openai/qwen-plus", "batch_date": "2026-01-26", "industry_id": 1, "source_urls": [], "from_hot_news": false, "industry_name": "科技数码", "generator_version": "v1.0.0"}', '2026-01-26', 'industry_1::AI芯片能效比实测', 0, '2026-01-25 17:13:24.074344+00', NULL);
INSERT INTO "public"."sys_topic" ("id", "title", "industry_id", "potential_score", "heat_index", "reason", "keywords", "platform_heat", "heat_sources", "trend", "industry_tags", "target_audience", "creative_angles", "content_outline", "format_suggestions", "material_clues", "risk_notes", "source_info", "batch_date", "source_uid", "status", "created_time", "updated_time") VALUES (18, '‘科技股大跌’刷屏背后：普通人该重新理解的3个数码消费新常识', 1, 91, 89, '以大众视角解读热点事件，将艰涩的资本市场语言转化为普通数码消费者可感知的决策逻辑，强化科技媒体‘翻译者’角色，适合短视频与图文双端分发。', '[{"tag": "科技股", "type": "trend", "weight": 87.0}, {"tag": "数码消费观", "type": "core", "weight": 94.0}, {"tag": "认知升级", "type": "long_tail", "weight": 82.0}]', '{"douyin": {"rank": 2, "score": 85.0, "mentions": 53}, "xiaohongshu": {"rank": 1, "score": 91.0, "mentions": 67}}', '[{"url": "https://wallstreetcn.com/articles/3764002", "rank": 3, "title": "美联储决议+中美数据+科技巨头财报！全球市场进入“风暴眼”", "last_time": "2026-01-25T00:29:00", "first_time": "2026-01-25T00:29:00", "platform_id": "wallstreetcn-hot", "platform_name": "华尔街见闻"}]', '{"level": "strong", "comment": "小红书‘科技股大跌’话题下，大量笔记标题含‘我该换手机吗’‘AirPods还能买吗’，显示强消费关联意图。", "direction": "up", "confidence": 0.89, "period_hours": 12}', '[{"industry_id": 1, "match_score": 100.0, "industry_name": "科技数码"}]', '{"age_range": "18-30", "interests": ["数码开箱", "消费决策", "财经小白", "学生党省钱"], "city_tiers": ["一线", "新一线", "二线"], "description": "对科技感兴趣但无金融背景的年轻人，常因热点新闻产生消费焦虑，需要简明、可信、去术语的行动指南。", "gender_ratio": "female_lean"}', '[{"hook": "股价跌≠产品不值，这3个判断标准比K线图更重要", "angle": "反常识科普", "description": "用‘维修成本占比’‘系统更新支持年限’‘配件通用性’替代‘是否龙头股’作为购买依据。"}]', '[{"title": "常识1：别看公司市值，要看你手里的设备还能‘活’几年", "points": ["举例：某品牌手机系统支持截止日早于硬件报废周期，实际使用成本翻倍", "查询方式：官网支持页面 / GSMArena数据库 / Reddit r/AndroidSupport"]}, {"title": "常识2：供应链越短，你的订单越不怕‘风暴眼’", "points": ["对比国产芯片/电池/屏幕厂商整机（如华为Mate系列）vs 全球分散采购机型（某美系品牌）的618发货延迟率", "给出‘供应链透明度’简易自查法（包装盒编码溯源、官网部件页披露程度）"]}, {"title": "常识3：二手流通性=隐形保险，3个平台残值率速查表", "points": ["闲鱼/转转/拍拍严选近30天同型号成交价波动幅度对比", "列出‘保值三要素’：官方以旧换新政策、维修手册开源度、社区刷机活跃度"]}]', '[{"note": "口播+大字幕+箭头标注关键数据，结尾固定Slogan：‘买数码，不看K线图，看生命周期表’。", "type": "short_video", "duration": "25-40秒", "platforms": ["抖音", "小红书"]}, {"note": "9宫格图文：每格1个常识+1张对比截图+1句结论，支持一键保存。", "type": "carousel", "duration": "", "platforms": ["小红书", "微信公众号"]}]', '[{"type": "data", "source": "爬虫采集闲鱼/转转API（合规授权）、品牌官网售后政策页", "description": "抓取主流电商平台近90天热门机型‘发布后第12月’二手均价，计算标准差与中位数。"}]', '[{"risk": "过度简化可能削弱专业性。", "level": "low", "advice": "在文末注明‘适用于日常消费决策，非投资建议’，并链接延伸阅读（如IDC供应链报告摘要）。"}]', '{"notes": "基于当日 TrendRadar 数据自动生成。", "ai_model": "openai/qwen-plus", "batch_date": "2026-01-26", "industry_id": 1, "source_urls": [{"url": "https://wallstreetcn.com/articles/3764002", "title": "美联储决议+中美数据+科技巨头财报！全球市场进入“风暴眼”"}], "from_hot_news": true, "industry_name": "科技数码", "generator_version": "v1.0.0"}', '2026-01-26', 'industry_1::数码消费新常识', 0, '2026-01-25 17:13:24.078041+00', NULL);
INSERT INTO "public"."sys_topic" ("id", "title", "industry_id", "potential_score", "heat_index", "reason", "keywords", "platform_heat", "heat_sources", "trend", "industry_tags", "target_audience", "creative_angles", "content_outline", "format_suggestions", "material_clues", "risk_notes", "source_info", "batch_date", "source_uid", "status", "created_time", "updated_time") VALUES (19, '黑科技预警：2026年Q1已量产的5项‘安静爆发’技术，多数人还没听过名字', 1, 96, 68, '避开财报季喧嚣，挖掘真正具有落地能力的前沿技术，塑造账号‘科技雷达’专业形象；标题制造信息差感，激发点击与收藏欲，属高潜力evergreen选题。', '[{"tag": "黑科技", "type": "core", "weight": 97.0}, {"tag": "技术前瞻", "type": "core", "weight": 93.0}, {"tag": "量产技术", "type": "trend", "weight": 89.0}]', '{"zhihu": {"rank": 4, "score": 81.0, "mentions": 14}}', '[]', '{"level": "medium", "comment": "无突发热点，但‘黑科技’类内容在知乎、B站属稳定高互动垂类，季度性盘点符合用户信息刷新节奏。", "direction": "flat", "confidence": 0.71, "period_hours": 72}', '[{"industry_id": 1, "match_score": 100.0, "industry_name": "科技数码"}]', '{"age_range": "22-38", "interests": ["极客", "科技趋势", "新产品尝鲜", "专利解读"], "city_tiers": ["一线", "新一线", "二线"], "description": "追求认知领先感的科技爱好者，愿为‘第一个知道’付费或投入时间，偏好硬核但不晦涩的解读。", "gender_ratio": "balanced"}', '[{"hook": "不是‘光子芯片’，是‘硅基光互连收发器’——听懂技术真名才不会被割韭菜", "angle": "命名解构法", "description": "逐个拆解技术名词构成（材料+原理+功能），对比厂商宣传语与IEEE论文定义差异。"}]', '[{"title": "1. 硅基光互连收发器（Intel/AMD已用于服务器CPU）", "points": ["解决什么问题：突破铜线带宽瓶颈，单通道达1.6Tbps", "消费者影响：未来台式机主板可能取消PCIe插槽，改用光接口"]}, {"title": "2. 电致变色AR镜片（华为Vision Glass第二代原型）", "points": ["无需供电即保持透光态，通电后0.3秒切换AR显示模式", "比MicroLED功耗低87%，是轻量化AR眼镜关键破局点"]}, {"title": "3. 基于RISC-V的AI协处理器（阿里平头哥Hanguang 1200）", "points": ["独立运行Llama3-8B本地推理，功耗仅2.1W", "已集成进钉钉会议硬件终端，2026年Q2将开放SDK"]}]', '[{"note": "每项技术配‘一句话本质’‘一张原理简图’‘一个用户场景’三段式结构。", "type": "article", "duration": "", "platforms": ["微信公众号", "知乎"]}]', '[{"type": "case", "source": "CES官方技术报告、MWC Press Release Archive、IEEE Xplore检索结果", "description": "梳理CES 2026、MWC 2026展会上确认量产的技术白皮书；交叉验证厂商官网新闻稿与IEEE Xplore论文发表时间。"}]', '[{"risk": "部分技术尚处早期商用，存在‘雷声大雨点小’预期落差风险。", "level": "medium", "advice": "严格限定‘已量产’范围（需提供产线照片、BOM表、渠道供货证明），避免使用‘即将上市’‘有望搭载’等模糊表述。"}]', '{"notes": "基于CES/MWC 2026展会及厂商公开技术路线图生成。", "ai_model": "openai/qwen-plus", "batch_date": "2026-01-26", "industry_id": 1, "source_urls": [], "from_hot_news": false, "industry_name": "科技数码", "generator_version": "v1.0.0"}', '2026-01-26', 'industry_1::安静爆发黑科技', 0, '2026-01-25 17:13:24.082067+00', NULL);
INSERT INTO "public"."sys_topic" ("id", "title", "industry_id", "potential_score", "heat_index", "reason", "keywords", "platform_heat", "heat_sources", "trend", "industry_tags", "target_audience", "creative_angles", "content_outline", "format_suggestions", "material_clues", "risk_notes", "source_info", "batch_date", "source_uid", "status", "created_time", "updated_time") VALUES (20, '从‘科技巨头财报’看真相：哪些数码功能正被悄悄砍掉？2026用户权益缩水清单', 1, 93.5, 84, '逆向解读财报中的成本优化动作，揭示厂商‘降本增配’背后的隐藏代价，切中用户对‘越买越亏’的普遍焦虑，具备强传播性与讨论价值。', '[{"tag": "科技巨头财报", "type": "trend", "weight": 90.0}, {"tag": "数码功能缩水", "type": "core", "weight": 95.0}, {"tag": "用户权益", "type": "long_tail", "weight": 88.0}]', '{"weibo": {"rank": 2, "score": 87.0, "mentions": 26}, "zhihu": {"rank": 3, "score": 83.0, "mentions": 19}}', '[{"url": "https://wallstreetcn.com/articles/3764002", "rank": 3, "title": "美联储决议+中美数据+科技巨头财报！全球市场进入“风暴眼”", "last_time": "2026-01-25T00:29:00", "first_time": "2026-01-25T00:29:00", "platform_id": "wallstreetcn-hot", "platform_name": "华尔街见闻"}]', '{"level": "strong", "comment": "微博#手机功能缩水#话题24小时内阅读破亿，知乎‘厂商偷偷阉割的功能’问题获127万浏览，情绪浓度极高。", "direction": "up", "confidence": 0.84, "period_hours": 24}', '[{"industry_id": 1, "match_score": 100.0, "industry_name": "科技数码"}]', '{"age_range": "25-45", "interests": ["数码维权", "参数党", "老用户忠诚度", "消费主义批判"], "city_tiers": ["一线", "新一线", "二线"], "description": "有多年数码使用经验、熟悉迭代规律的老用户，对‘新瓶装旧酒’高度敏感，乐于分享避坑经验。", "gender_ratio": "balanced"}', '[{"hook": "财报里写的‘优化运营效率’，在你手机里就是砍掉这个按钮", "angle": "财报条目对照法", "description": "直接引用财报原文段落，标注对应产品功能变更（如‘供应链协同费用下降12%’→ 取消独立充电IC导致快充兼容性下降）。"}]', '[{"title": "缩水项1：USB-C物理接口的‘假全功能’泛滥", "points": ["实测2026年上市的12款旗舰机型，仅3款支持DisplayPort Alt Mode与PD3.1双向充电同时启用", "根源：为省去一颗$0.12的协议芯片，厂商改用软件协商机制（成功率<63%）"]}, {"title": "缩水项2：影像算法的‘预设依赖症’", "points": ["对比2023 vs 2026旗舰机Raw直出宽容度下降1.8档（DxOMark数据）", "厂商策略：用更强AI算法掩盖传感器底子变薄，但牺牲手动创作空间"]}, {"title": "缩水项3：系统级隐私控制的‘名义开放’", "points": ["Android 15新增‘传感器权限细分’，但实测92% OEM定制UI未开放该开关", "财报佐证：‘系统UI研发支出同比降21%’"]}]', '[{"note": "每项缩水配‘财报原文截图’+‘产品实测动图’+‘用户替代方案’三栏排版。", "type": "article", "duration": "", "platforms": ["微信公众号", "知乎"]}]', '[{"type": "data", "source": "公司官网投资者关系页、SEC EDGAR数据库、第三方参数平台历史快照", "description": "下载2023–2026年各品牌年报PDF，用OCR提取‘研发’‘供应链’‘运营’相关章节；交叉验证GSMArena、PhoneArena参数库变更日志。"}]', '[{"risk": "可能引发厂商公关反弹或法律函警告。", "level": "high", "advice": "所有结论必须有财报原文、第三方实测、用户众测三重证据链；声明‘不针对具体品牌，仅反映行业共性策略’。"}]', '{"notes": "基于当日 TrendRadar 数据自动生成。", "ai_model": "openai/qwen-plus", "batch_date": "2026-01-26", "industry_id": 1, "source_urls": [{"url": "https://wallstreetcn.com/articles/3764002", "title": "美联储决议+中美数据+科技巨头财报！全球市场进入“风暴眼”"}], "from_hot_news": true, "industry_name": "科技数码", "generator_version": "v1.0.0"}', '2026-01-26', 'industry_1::数码功能缩水清单', 0, '2026-01-25 17:13:24.08545+00', NULL);
